def count_vowels(s):
    count = 0
    for char in s.lower():
        if char in 'aeiou':
            count += 1
    return count

def word_count(text):
    counts = {}
    for word in text.lower().split():
        counts[word] = counts.get(word, 0) + 1
    return counts

def safe_read_numbers(filename):
    numbers = []
    try:
        with open(filename, 'r') as f:
            for line_num, line in enumerate(f, 1):
                try:
                    numbers.append(float(line.strip()))
                except ValueError:
                    print(f'Warning: Line {line_num} is not a valid number: {line.strip()!r}')
    except FileNotFoundError:
        print(f'Error: File {filename!r} not found.')
    return numbers

class Student:
    def __init__(self, name):
        self.name = name
        self.grades = []

    def add_grade(self, grade):
        self.grades.append(grade)

    def gpa(self):
        if not self.grades:
            return 0.0
        return sum(self.grades) / len(self.grades)

    def __str__(self):
        return f'Student({self.name}, GPA: {self.gpa():.2f})'

def power(base, exp):
    if exp == 0:
        return 1
    return base * power(base, exp - 1)
